window.__sage_i18n = {"en":{"meta":{"title":"Salón Lumi · premium hair salon in Prague","description":"A premium hair salon in central Prague. Cuts, colour and balayage with a team that listens. Book online — first consultation is free."},"a11y":{"skip":"Skip to content"},"nav":{"salon":"About","services":"Services","team":"Team","gallery":"Lookbook","contact":"Contact","book":"Book online","social":"Social"},"hero":{"eyebrow":"Premium hair salon · Prague 2","brand":"Salón","brand_italic":"Lumi","line":"Cut · Colour · Balayage · Care","sub":"Hairstylists who actually listen. Honest advice and a colour or cut that fits both your hair and your everyday life."},"marquee":{"i1":"Cuts tailored to you","i2":"Balayage and lightening","i3":"Olaplex care","i4":"Bridal styling","i5":"First consultation is free"},"about":{"label":"About the salon","title":"A small Prague salon where the focus is on you, your hair and the result","p1":"In central Prague since 2018. The team hardly changes, the salon stays small on purpose — your stylist always has time to listen.","p2":"We specialise in long hair and colour that grows out beautifully — balayage, foliage and soft highlights. No harsh bleach, no monthly fixes."},"stats":{"s1":"years on Vinohradská","s2":"happy clients","s3":"stylists in our team","s4":"BOMTON CUP nominations"},"services":{"label":"Services","title":"Hair care that <em>fits your life</em>","lead":"A short overview of what we do — pick what speaks to you. The first consultation is always free, with no obligation.","s1":{"title":"Cuts tailored to you","desc":"A cut shaped around your face, hair type and the way you actually wear it. Always starts with a short conversation about what you want.","price":"From <strong>35 €</strong>"},"s2":{"title":"Colour and toning","desc":"A shade chosen to look natural, elegant and harmonic — never overdone. Ammonia-free options available on request.","price":"From <strong>65 €</strong>"},"s3":{"title":"Balayage and lightening","desc":"Hand-painted highlights that add depth and a little lightness — without harsh contrasts and without high-maintenance roots.","price":"From <strong>95 €</strong>"},"s4":{"title":"Care and regeneration","desc":"Olaplex, hair botox and bonding treatments. Premium care that we'll only recommend when your hair really needs it.","price":"From <strong>25 €</strong>"}},"quote":{"text":"We know <em>how much</em> your hair matters. That's why every visit starts with a real conversation, never with a sales pitch — and we always show you the colour in daylight before we begin.","sub":"— the Lumi team"},"team":{"label":"The team","title":"Behind every visit, <em>experienced hands</em>","lead":"A small team that's been together for years. Each of us specialises in something different — pick whoever's work feels closest to yours.","p1":{"name":"Ema Nováková","role":"Top stylist · 8 years"},"p2":{"name":"Lucia Veselá","role":"Colour specialist · 6 years"},"p3":{"name":"Hana Krajčová","role":"Bridal & styling · 5 years"},"p4":{"name":"Klára Dušková","role":"Junior stylist · 2 years"}},"lookbook":{"label":"Lookbook","title":"A few recent <em>transformations</em>","lead":"A small selection of cuts and colour transformations from the past few months."},"reviews":{"label":"Client voices","title":"What our clients <em>say</em>","t1":{"quote":"After my first visit I just kept coming back, and I've been a regular for three years now. I trust Ema with my hair more than anyone else in this city.","name":"Dominika","role":"Client since 2021"},"t2":{"quote":"The best balayage in Prague. You can see they really know what they're doing — and they never push me into more expensive services.","name":"Zuzana","role":"Client since 2020"},"t3":{"quote":"Lovely interior, good coffee, professional team. I recommend them to all my friends — and for long hair they're the best in the city.","name":"Veronika","role":"Client since 2022"},"t4":{"quote":"Lucia gave me a darker shade for winter, and we moved to a soft balayage for the summer. It still looks completely natural — thank you!","name":"Petra","role":"Client since 2023"},"t5":{"quote":"I originally came in just for a cut. Today my whole family goes there — including my daughter.","name":"Andrea","role":"Client since 2019"}},"faq":{"label":"FAQ","title":"Common <em>questions</em>","q1":"How far in advance should I book?","a1":"About a week ahead for a cut and two weeks for colour. Around Christmas and just before summer, plan three weeks ahead.","q2":"Do you offer a consultation before the first visit?","a2":"Yes — fifteen minutes, free of charge, by email or phone. Just send us a few photos of your hair and we'll let you know whether what you want is realistic.","q3":"Where can I park?","a3":"Blue zone right outside the salon, or in the OC Flora paid car park, a 5-minute walk away.","q4":"Do you accept card payments?","a4":"Yes — card, cash, Apple Pay and Google Pay."},"contact":{"label":"Contact","title":"Open today until 19:00","lead":"Online booking is open 24/7. By phone, you can reach us during opening hours.","address":"Vinohradská 24, 120 00 Prague 2","hours_mon":"Mon–Fri 9:00 – 19:00","hours_sat":"Sat 9:00 – 14:00","hours_sun":"Sun closed","btn_call":"Call us"},"cookies":{"text":"We use cookies to give you a better experience.","accept":"Accept","decline":"Decline"},"footer":{"rights":"© 2026 Salón Lumi","privacy":"Privacy policy"},"svc_pg":{"meta_title":"Services and price list · Salón Lumi","meta_desc":"Our complete service menu and price list — cuts, colour, balayage, care and bridal styling. Always with a free consultation.","crumb_home":"Salón Lumi","crumb":"Services","title":"Our complete <em>price list</em>","lead":"Every appointment starts with a short, free consultation. The prices below are starting points; we'll always agree the final price before we begin.","cuts":{"num":"01 — Cuts","title":"Cuts tailored <em>to you</em>","desc":"A cut shaped to your face, hair density and the way you really wear it. We finish with a short styling lesson so the look survives the next morning at home.","r1":{"name":"Women's tailored cut","desc":"Wash, signature cut and finish styling. Includes a consultation and a simple post-cut care plan.","time":"90 min","price":"from 45 €"},"r2":{"name":"Long-hair cut & shape","desc":"A specialised approach for hair past the shoulders — soft layering, ends repaired and length preserved.","time":"90 min","price":"from 55 €"},"r3":{"name":"Fringe trim","desc":"A maintenance trim between full cuts — book within 6 weeks of your last visit.","time":"20 min","price":"15 €"},"r4":{"name":"Men's cut & beard","desc":"Scissor or clipper cut with a hot-towel finish. Beard trim available as an add-on.","time":"45 min","price":"from 35 €"}},"col":{"num":"02 — Colour","title":"Colour and <em>toning</em>","desc":"We work with Wella, Olaplex and ammonia-free systems. We always patch-test new clients and show you the colour swatch in your own daylight before we begin.","r1":{"name":"Roots refresh","desc":"Maintenance colour at the roots, blended into your existing tone. Best 6–8 weeks after your last visit.","time":"90 min","price":"from 65 €"},"r2":{"name":"Full single-tone colour","desc":"From roots to ends in a single chosen tone. Includes a glaze finish for shine.","time":"2.5 h","price":"from 95 €"},"r3":{"name":"Glaze / gloss","desc":"A 20-minute treatment to refresh tone and shine — perfect between full colours.","time":"30 min","price":"35 €"},"r4":{"name":"Grey blending","desc":"A soft, low-maintenance way to blend in greys so they grow out gracefully — without a hard line at the roots.","time":"2 h","price":"from 85 €"}},"bal":{"num":"03 — Balayage and lightening","title":"Soft <em>balayage</em> and lightening","desc":"Our signature service. Hand-painted, never harsh and always supported by Olaplex. The final price depends on length and density — we'll confirm it at the consultation.","r1":{"name":"Partial balayage","desc":"Lighter pieces around the face and parting. Ideal for first-timers or for a low-maintenance refresh.","time":"2.5 h","price":"from 120 €"},"r2":{"name":"Full-head balayage","desc":"Hand-painted lightening across the whole canopy, finished with a tonal glaze for depth.","time":"3.5 h","price":"from 180 €"},"r3":{"name":"Foilyage / dimensional","desc":"Balayage with foil-pressed accents for a brighter result while keeping the roots soft.","time":"3.5 h","price":"from 195 €"},"r4":{"name":"Colour correction","desc":"For clients fixing a previous service. Always preceded by a paid 30-minute strand-test consultation a week before.","time":"by quote","price":"by quote"}},"care":{"num":"04 — Care","title":"Repair and <em>regeneration</em>","desc":"In-salon treatments and at-home programmes. We'll only recommend a treatment if your hair actually needs it — we'd rather you came in less often than spent more than you should.","r1":{"name":"Olaplex treatment","desc":"A targeted bond-rebuilder for hair stressed by colour, heat or extensions. We recommend it every 4–6 weeks.","time":"45 min","price":"35 €"},"r2":{"name":"K18 deep mask","desc":"A 4-minute peptide mask that rebuilds keratin chains. Best paired with colour services.","time":"30 min","price":"42 €"},"r3":{"name":"Scalp ritual","desc":"A massage-led scalp cleanse — exfoliation, oil dissolve and a 12-minute pressure-point release.","time":"40 min","price":"38 €"},"r4":{"name":"Bridal trial + wedding day","desc":"A pre-wedding trial run plus styling on the day. Includes a moodboard call and travel within Prague 1–10.","time":"2 visits","price":"from 280 €"}},"add":{"title":"Common add-ons","lead":"Add to any service when you book. We'll only suggest what your hair actually needs.","a1":{"name":"Long-hair surcharge (past mid-back)","price":"+15 €"},"a2":{"name":"Glaze tone refresh","price":"+25 €"},"a3":{"name":"K18 in-shower booster","price":"+18 €"},"a4":{"name":"Blow-dry style finish","price":"+22 €"},"a5":{"name":"Eyebrow tint","price":"+12 €"},"a6":{"name":"Take-home Olaplex No. 3","price":"+28 €"}},"vou":{"eyebrow":"A gift that lasts","title":"Salon vouchers, <em>printed by hand</em>","text":"A voucher for any service or for an open amount (from 30 €). Hand-pressed on cotton card, ready in two working days. Valid 12 months.","cta":"Order a voucher →"}},"team_pg":{"meta_title":"Our team · Salón Lumi","meta_desc":"Meet the Lumi stylists — eight years of practice, four BOMTON CUP nominations and a clear focus on long hair, balayage and bridal.","crumb_home":"Salón Lumi","crumb":"Team","title":"Five stylists, <em>one salon</em>","lead":"A small, deliberately quiet team. Each of us specialises in something different — pick the stylist whose work speaks to you, or let us match you at the consultation.","m_yrs":"Years","m_lang":"Speaks","m_book":"Book with","m_book_cta":"Book →","s1":{"role":"Top stylist · founder","name":"Ema Nováková","b1":"Ema founded Lumi in 2018 after seven years between Berlin and Prague. Wella Master Colour Expert, three-time BOMTON CUP finalist. Her chair specialises in long, layered hair.","b2":"Always a 15-minute consultation before a first colour. Never more than two levels lifted in one session. Clients come back every six weeks or so.","t1":"Long-hair specialist","t2":"Soft balayage","t3":"Wella master colour","t4":"Bridal trials","yrs":"8","lang":"CZ · EN"},"s2":{"role":"Colour specialist","name":"Lucia Veselá","b1":"Our resident colourist since 2020. Trained under Goldwell in Vienna. Runs the salon's correction work — long sessions, always with a strand-test the week before.","b2":"Her speciality is grey integration — out of the monthly root cycle, into a tone that grows out gracefully. If you're tired of constant maintenance, this is her chair.","t1":"Colour correction","t2":"Grey integration","t3":"Goldwell certified","t4":"Glossing","yrs":"6","lang":"CZ · DE · EN"},"s3":{"role":"Bridal & editorial","name":"Hana Krajčová","b1":"Joined Lumi in 2021 after four seasons styling for Czech Vogue and the opening team at Augustine. Spring–autumn weddings; winter editorials.","b2":"Always a trial — never a day-of surprise. Travels for ceremonies across Czechia and Slovakia. A moodboard call is included in every wedding fee.","t1":"Bridal styling","t2":"Editorial","t3":"Updo / event","t4":"Travels for weddings","yrs":"5","lang":"SK · CZ · EN"},"s4":{"role":"Junior stylist","name":"Klára Dušková","b1":"Finished her apprenticeship at Lumi in 2024 and now runs her own chair. Trained alongside Ema for two years; Olaplex Level 2.","b2":"Booking with Klára is 20% below senior rates — we want her to grow with clients who genuinely like her style.","t1":"Cuts","t2":"Roots refresh","t3":"Olaplex Lvl 2","t4":"Junior rate","yrs":"2","lang":"CZ · EN"},"ba":{"label":"Before · After","title":"A few <em>recent transformations</em>","lead":"Six clients who let us share their photos. The look on the right is always how their hair looked at the end of the appointment — never re-styled at home for the photo.","b1":{"cat":"Soft balayage · Ema","title":"From box-dye to a low-maintenance soft balayage","note":"Three sessions, eight weeks apart. Olaplex on every visit and no foils above level 7."},"b2":{"cat":"Long-hair shape · Ema","title":"Length preserved, weight removed and the ends rebuilt","note":"A single visit. We took two centimetres off the length and 20% of the weight from the mid-lengths."},"b3":{"cat":"Grey integration · Lucia","title":"Out of monthly root touch-ups, into a soft natural blend","note":"Two visits, six months apart. We stretched the regrowth and pulled cool tones through the mid-lengths."},"b4":{"cat":"Bridal trial · Hana","title":"A loose, romantic updo for a Český Krumlov wedding","note":"Trial on the Tuesday, the real day on the Saturday. The bride asked for nothing pinned at the temples."},"b5":{"cat":"Colour correction · Lucia","title":"From a brassy lift back to a clean, even, cool blonde","note":"A four-hour correction with a strand-test the week before. Glaze refresh four weeks later."},"b6":{"cat":"First haircut · Klára","title":"A first proper cut in two years — soft layers and a fresh fringe","note":"Ninety minutes, no colour. We dry-cut the layers after the wash to read the natural fall of the hair."}}},"book_pg":{"meta_title":"Book online · Salón Lumi","meta_desc":"Pick a service, a stylist and a time — confirmed in writing within four working hours. A free 15-minute consultation is always included.","crumb_home":"Salón Lumi","crumb":"Book online","title":"Book <em>your visit</em>","lead":"Four short steps. We'll confirm in writing within four working hours, and a free 15-minute consultation is always included before any colour service.","step1":{"num":"Step 01","label":"Service"},"step2":{"num":"Step 02","label":"Stylist"},"step3":{"num":"Step 03","label":"Date and time"},"step4":{"num":"Step 04","label":"Your details"},"s1":{"title":"What can we <em>do for you?</em>","lead":"Pick the closest match — we'll fine-tune at the consultation. The long-hair surcharge applies if your hair is longer than mid-back.","o1":{"name":"Tailored cut","meta":"90 min · with consultation","price":"from 45 €"},"o2":{"name":"Long-hair cut & shape","meta":"90 min · for hair past the shoulder","price":"from 55 €"},"o3":{"name":"Roots refresh","meta":"90 min · regrowth + glaze","price":"from 65 €"},"o4":{"name":"Full single-tone colour","meta":"2.5 h · roots to ends","price":"from 95 €"},"o5":{"name":"Full-head balayage","meta":"3.5 h · hand-painted","price":"from 180 €"},"o6":{"name":"Olaplex treatment","meta":"45 min · bond rebuild","price":"35 €"},"o7":{"name":"Bridal trial + wedding day","meta":"2 h · trial + wedding day","price":"from 280 €"},"o8":{"name":"Consultation only","meta":"20 min · before colour or correction","price":"free"}},"s2":{"title":"Pick <em>your stylist</em>","lead":"Or let us match you — we'll suggest the right person based on the service, your hair length and who has space the week you want.","any":{"name":"Match me","role":"No preference"},"ema":{"name":"Ema Nováková","role":"Top stylist"},"lucia":{"name":"Lucia Veselá","role":"Colour"},"hana":{"name":"Hana Krajčová","role":"Bridal"},"klara":{"name":"Klára Dušková","role":"Junior · −20 %"}},"s3":{"title":"Pick a <em>date and time</em>","lead":"A live view of openings for the next ten working days. Saturday afternoons usually fill up first — book three weeks ahead in spring and December.","d1":"Tue 12 May","d1c":"3 slots","d2":"Wed 13 May","d2c":"5 slots","d3":"Thu 14 May","d3c":"full","d4":"Fri 15 May","d4c":"2 slots","d5":"Sat 16 May","d5c":"1 slot","d6":"Mon 18 May","d6c":"6 slots"},"s4":{"title":"A few <em>final details</em>","lead":"We'll text you a confirmation within four working hours. Free cancellation up to twenty-four hours before your visit.","f":{"name_label":"Your name","name_ph":"Anna Nováková","phone_label":"Phone","phone_ph":"+420 770 111 222","email_label":"E-mail","email_ph":"anna@example.cz","notes_label":"Anything we should know?","notes_ph":"Photo of recent colour / sensitivities / preferred stylist…"},"sum":{"title":"Your booking","svc":"Service","svcEmpty":"— pick a service","styl":"Stylist","stylEmpty":"— anyone","when":"When","whenEmpty":"— pick a date","price":"Price","priceEmpty":"— set at consultation"}},"actions":{"prev":"← Back","next":"Continue →"}}},"sk":{"meta":{"title":"Salón Lumi · prémiové kaderníctvo Praha","description":"Prémiové kaderníctvo v centre Prahy. Strih, farba a balayage v tíme, ktorý vás vie počúvať. Online rezervácia — prvá konzultácia zadarmo."},"a11y":{"skip":"Preskočiť na obsah"},"nav":{"salon":"O nás","services":"Služby","team":"Tím","gallery":"Lookbook","contact":"Kontakt","book":"Rezervovať online","social":"Sociálne siete"},"hero":{"eyebrow":"Prémiové kaderníctvo · Praha 2","brand":"Salón","brand_italic":"Lumi","line":"Strih · Farba · Balayage · Starostlivosť","sub":"Kaderníčky, ktoré vás naozaj počúvajú. Úprimná rada a strih alebo farba, ktorá pasuje k vašim vlasom aj k vášmu každodennému životu."},"marquee":{"i1":"Strihy na mieru","i2":"Balayage a zosvetlenie","i3":"Starostlivosť Olaplex","i4":"Svadobný styling","i5":"Prvá konzultácia zadarmo"},"about":{"label":"O salóne","title":"Malý pražský salón, kde sa točí všetko okolo vás, vašich vlasov a výsledku","p1":"V centre Prahy od roku 2018. Tím sa nemení, salón zostáva malý zámerne — vaša kaderníčka na vás má vždy čas.","p2":"Špecializujeme sa na dlhé vlasy a farbenie, ktoré pekne zarastá — balayage, foliage a jemný melír. Bez agresívneho odfarbovania."},"stats":{"s1":"rokov na Vinohradskej","s2":"spokojných klientok","s3":"kaderníčok v tíme","s4":"nominácií · BOMTON CUP"},"services":{"label":"Služby","title":"Starostlivosť, ktorá <em>pasuje do vášho života</em>","lead":"Krátky prehľad toho, čo robíme — vyberte si, čo je pre vás. Prvá konzultácia je vždy zadarmo a k ničomu vás nezaväzuje.","s1":{"title":"Strihy na mieru","desc":"Strih navrhnutý podľa tvaru tváre, typu vlasov a toho, ako vlasy reálne nosíte. Vždy začneme krátkym rozhovorom o tom, čo si predstavujete.","price":"Od <strong>35 €</strong>"},"s2":{"title":"Farbenie a tónovanie","desc":"Odtieň zvolíme tak, aby vyzeral prirodzene, elegantne a zladene — nikdy nie cez čiaru. Na požiadanie aj bez amoniaku.","price":"Od <strong>65 €</strong>"},"s3":{"title":"Balayage a zosvetlenie","desc":"Ručne maľované pramienky, ktoré pridajú vlasom hĺbku a trochu rozjasnenia — bez ostrých kontrastov a bez náročného odrastu.","price":"Od <strong>95 €</strong>"},"s4":{"title":"Starostlivosť a regenerácia","desc":"Olaplex, hair botox a bonding ošetrenie. Prémiová starostlivosť, ktorú vám odporučíme len vtedy, keď ju vaše vlasy naozaj potrebujú.","price":"Od <strong>25 €</strong>"}},"quote":{"text":"Vieme, <em>ako veľmi</em> na vlasoch záleží. Preto začíname rozhovorom, nikdy vás netlačíme do zbytočných služieb a odtieň farby vám ukážeme ešte pred začiatkom.","sub":"— tím Lumi"},"team":{"label":"Tím","title":"Za každou návštevou stoja <em>skúsené ruky</em>","lead":"Malý tím, ktorý je spolu už roky. Každá z nás sa špecializuje na niečo iné — vyberte si tú, ktorej štýl je vám najbližší.","p1":{"name":"Ema Nováková","role":"Top stylistka · 8 rokov"},"p2":{"name":"Lucia Veselá","role":"Špecialistka na farbu · 6 rokov"},"p3":{"name":"Hana Krajčová","role":"Svadby a styling · 5 rokov"},"p4":{"name":"Klára Dušková","role":"Junior stylistka · 2 roky"}},"lookbook":{"label":"Lookbook","title":"Pár nedávnych <em>premien</em>","lead":"Malý výber strihov a farebných premien z posledných mesiacov."},"reviews":{"label":"Hlasy klientok","title":"Čo o nás <em>hovoria klientky</em>","t1":{"quote":"Po prvej návšteve som tam jednoducho zostala chodiť — a som tam pravidelne už tri roky. Eme dôverujem svoje vlasy ako nikomu inému v meste.","name":"Dominika","role":"Klientka od 2021"},"t2":{"quote":"Najlepšie balayage v Prahe. Je vidno, že naozaj vedia, čo robia. A nikdy ma netlačia do drahších služieb.","name":"Zuzana","role":"Klientka od 2020"},"t3":{"quote":"Príjemný interiér, dobrá káva, profesionálny tím. Odporúčam ich všetkým kamarátkam — a na dlhé vlasy sú top v meste.","name":"Veronika","role":"Klientka od 2022"},"t4":{"quote":"Lucia mi v zime spravila tmavšiu farbu, na leto sme prešli na svetlejšie balayage. Stále to vyzerá úplne prirodzene. Ďakujem!","name":"Petra","role":"Klientka od 2023"},"t5":{"quote":"Pôvodne som tam šla iba na strih. Dnes tam chodí celá moja rodina — vrátane mojej dcéry.","name":"Andrea","role":"Klientka od 2019"}},"faq":{"label":"FAQ","title":"Časté <em>otázky</em>","q1":"Ako dlho dopredu sa mám objednať?","a1":"Pri strihu zvyčajne týždeň, pri farbení dva týždne. Pred Vianocami a pred letom rátajte radšej s tromi týždňami.","q2":"Robíte konzultácie pred prvou návštevou?","a2":"Áno — 15 minút zadarmo, e-mailom alebo telefonicky. Stačí poslať pár fotiek vlasov a my vám napíšeme, či sa to, čo chcete, dá zariadiť.","q3":"Kde sa dá zaparkovať?","a3":"Modrá zóna priamo pred salónom alebo platený parkovací dom OC Flora 5 minút pešo.","q4":"Akceptujete platby kartou?","a4":"Áno — kartou, hotovosťou, Apple Pay aj Google Pay."},"contact":{"label":"Kontakt","title":"Dnes otvorené do 19:00","lead":"Online rezervácia funguje 24/7. Telefonicky nás zastihnete počas otváracích hodín.","address":"Vinohradská 24, 120 00 Praha 2","hours_mon":"Po–Pi 9:00 – 19:00","hours_sat":"So 9:00 – 14:00","hours_sun":"Ne zatvorené","btn_call":"Zavolať"},"cookies":{"text":"Používame cookies, aby sme vám poskytli lepší zážitok.","accept":"Prijať","decline":"Odmietnuť"},"footer":{"rights":"© 2026 Salón Lumi","privacy":"Ochrana osobných údajov"},"svc_pg":{"meta_title":"Služby a cenník · Salón Lumi","meta_desc":"Kompletná ponuka a cenník — strihy, farbenie, balayage, starostlivosť a svadobný styling. Vždy s konzultáciou zadarmo.","crumb_home":"Salón Lumi","crumb":"Služby","title":"Náš kompletný <em>cenník</em>","lead":"Každú návštevu otvárame krátkou konzultáciou zadarmo. Ceny nižšie sú orientačné; konečnú cenu odsúhlasíme spoločne pred začiatkom.","cuts":{"num":"01 — Strihy","title":"Strihy <em>na mieru</em>","desc":"Strih, ktorý sedí vašej tvári, hustote vlasov a tomu, ako vlasy reálne nosíte. Na záver vám ukážeme krátky styling, aby look prežil aj ráno doma.","r1":{"name":"Dámsky strih na mieru","desc":"Umytie, signature strih a styling. V cene konzultácia a jednoduchý plán starostlivosti po strihu.","time":"90 min","price":"od 45 €"},"r2":{"name":"Strih dlhých vlasov","desc":"Špecializovaný prístup pre vlasy pod plecia — jemné vrstvenie, ošetrenie končekov a zachovanie dĺžky.","time":"90 min","price":"od 55 €"},"r3":{"name":"Zastrihnutie ofiny","desc":"Údržbové zastrihnutie medzi celými strihmi — rezervujte do 6 týždňov od poslednej návštevy.","time":"20 min","price":"15 €"},"r4":{"name":"Pánsky strih + brada","desc":"Strihanie nožnicami alebo strojčekom s finišom horúcim uterákom. Úpravu brady pridáme ako doplnok.","time":"45 min","price":"od 35 €"}},"col":{"num":"02 — Farbenie","title":"Farbenie a <em>tónovanie</em>","desc":"Pracujeme s Wellou, Olaplexom a bezamoniakovými systémami. Novým klientkam vždy robíme test a odtieň ukážeme v dennom svetle ešte pred začiatkom.","r1":{"name":"Korekcia odrastov","desc":"Údržbové farbenie pri korienkoch, jemne zladené s existujúcim odtieňom. Najlepšie 6–8 týždňov po poslednej návšteve.","time":"90 min","price":"od 65 €"},"r2":{"name":"Plné jednotónové farbenie","desc":"Od korienkov po končeky v jednom zvolenom odtieni. V cene aj glaze finiš pre lesk.","time":"2,5 h","price":"od 95 €"},"r3":{"name":"Glaze / gloss","desc":"20-minútové ošetrenie na osvieženie tónu a lesku — ideálne medzi farbeniami.","time":"30 min","price":"35 €"},"r4":{"name":"Integrácia šedín","desc":"Jemné, nenápadné prepojenie šedín, ktoré pekne zarastajú. Bez ostrej hranice pri korienkoch.","time":"2 h","price":"od 85 €"}},"bal":{"num":"03 — Balayage a zosvetlenie","title":"Jemné <em>balayage</em> a zosvetlenie","desc":"Naša signature služba. Maľované rukou, nikdy nie ostré, vždy s podporou Olaplexu. Cena závisí od dĺžky a hustoty — odsúhlasíme ju pri konzultácii.","r1":{"name":"Čiastočné balayage","desc":"Pramienky okolo tváre a pri pesinke. Ideálne pri prvom balayage alebo na nenáročné osvieženie.","time":"2,5 h","price":"od 120 €"},"r2":{"name":"Plné balayage","desc":"Maľované rozjasnenie po celej hlave, finišované tónujúcim glazem pre rozmer.","time":"3,5 h","price":"od 180 €"},"r3":{"name":"Foilyage / dimension","desc":"Balayage s fóliovými akcentmi pre svetlejší výsledok pri zachovaní mäkkých korienkov.","time":"3,5 h","price":"od 195 €"},"r4":{"name":"Korekcia farby","desc":"Pre klientky, ktoré opravujú predchádzajúcu službu. Vždy s platenou 30-min strand-test konzultáciou týždeň vopred.","time":"podľa rozsahu","price":"podľa rozsahu"}},"care":{"num":"04 — Starostlivosť","title":"Oprava a <em>regenerácia</em>","desc":"Salónne ošetrenia a domáce programy. Neodporúčame ošetrenia, ktoré vlasy nepotrebujú — radšej prídete menej často, než aby ste platili viac, ako je nutné.","r1":{"name":"Olaplex samostatne","desc":"Cielené obnovenie väzieb pre vlasy zaťažené farbením, teplom alebo predĺžením. Odporúčame každé 4–6 týždňov.","time":"45 min","price":"35 €"},"r2":{"name":"K18 hĺbková maska","desc":"4-minútová peptidová maska, ktorá obnovuje keratínové reťazce. Najlepšie v kombinácii s farbením.","time":"30 min","price":"42 €"},"r3":{"name":"Rituál pokožky","desc":"Hĺbkové čistenie pokožky s masážou — peeling, rozpustenie olejov a 12-min uvoľnenie tlakových bodov.","time":"40 min","price":"38 €"},"r4":{"name":"Svadobná skúška + deň svadby","desc":"Predsvadobná skúška plus styling v deň svadby. V cene aj úvodná videokonzultácia podľa moodboardu a doprava v rámci Prahy 1–10.","time":"2 návštevy","price":"od 280 €"}},"add":{"title":"Bežné doplnky","lead":"Pridajte k akejkoľvek službe pri rezervácii. Odporučíme len to, čo vaše vlasy reálne potrebujú.","a1":{"name":"Príplatok za dlhé vlasy (pod stred chrbta)","price":"+15 €"},"a2":{"name":"Glaze osvieženie tónu","price":"+25 €"},"a3":{"name":"K18 in-shower booster","price":"+18 €"},"a4":{"name":"Styling fénovaním","price":"+22 €"},"a5":{"name":"Tónovanie obočia","price":"+12 €"},"a6":{"name":"Olaplex No. 3 domov","price":"+28 €"}},"vou":{"eyebrow":"Darček, ktorý ostáva","title":"Salónne poukazy, <em>tlačené ručne</em>","text":"Poukaz na ľubovoľnú službu alebo na otvorenú sumu (od 30 €). Ručne tlačený na bavlnenom papieri, hotový do 2 dní. Platnosť 12 mesiacov.","cta":"Objednať poukaz →"}},"team_pg":{"meta_title":"Náš tím · Salón Lumi","meta_desc":"Spoznajte stylistky Lumi — osem rokov praxe, štyri nominácie na BOMTON CUP a špecializácia na dlhé vlasy, balayage a svadby.","crumb_home":"Salón Lumi","crumb":"Tím","title":"Päť stylistiek, <em>jeden salón</em>","lead":"Malý, zámerne tichý tím. Každá z nás sa špecializuje na niečo iné — vyberte si tú, ktorej práca k vám hovorí, alebo vás napárujeme pri konzultácii.","m_yrs":"Roky","m_lang":"Jazyk","m_book":"Rezervovať u","m_book_cta":"Rezervovať →","s1":{"role":"Top stylistka · zakladateľka","name":"Ema Nováková","b1":"Ema založila Lumi v roku 2018 po siedmich rokoch v Berlíne a Prahe. Wella Master Colour Expert, tri roky finalistka BOMTON CUP. Špecialistka na dlhé vrstvené vlasy.","b2":"Pred prvým farbením vždy 15-minútová konzultácia. V jednej návšteve nezosvetľuje viac ako dva levely. Klientky chodia cca každých 6 týždňov.","t1":"Špecialistka na dlhé vlasy","t2":"Jemný balayage","t3":"Wella master colour","t4":"Svadobné skúšky","yrs":"8","lang":"CZ · EN"},"s2":{"role":"Špecialistka na farbu","name":"Lucia Veselá","b1":"Naša rezidenčná koloristka od 2020. Goldwell certifikácia vo Viedni. V salóne vedie korekcie farieb — práce na 4–5 hodín, vždy s predchádzajúcim strand-testom.","b2":"Špecializuje sa na integráciu šedín — z mesačných korekcií do tónu, ktorý sa pekne zarastá. Keď vás unavuje cyklus údržby, je jej kreslo pre vás.","t1":"Korekcia farby","t2":"Integrácia šedín","t3":"Goldwell certified","t4":"Glossing","yrs":"6","lang":"CZ · DE · EN"},"s3":{"role":"Svadby a editorial","name":"Hana Krajčová","b1":"V Lumi od 2021. Predtým štyri sezóny pre Czech Vogue a otvárala tím hotela Augustine. Jar–jeseň svadby, v zime editorialy.","b2":"Vždy so skúškou — žiadny deň svadby bez prípravy. Cestuje na obrady po ČR aj SR. Úvodná videokonzultácia s moodboardom je v cene.","t1":"Svadobný styling","t2":"Editorial","t3":"Účes / event","t4":"Cestuje za svadbou","yrs":"5","lang":"SK · CZ · EN"},"s4":{"role":"Junior stylistka","name":"Klára Dušková","b1":"Učňovku v Lumi dokončila v 2024, teraz vedie vlastné kreslo. Dva roky sa učila popri Eme, Olaplex Level 2.","b2":"Rezervácia u Kláry je o 20 % nižšia ako seniorské sadzby — chceme, aby rástla s klientkami, ktorým sa páči jej štýl.","t1":"Strihy","t2":"Korekcia odrastov","t3":"Olaplex Lvl 2","t4":"Junior cena","yrs":"2","lang":"CZ · EN"},"ba":{"label":"Pred · Po","title":"Pár nedávnych <em>premien</em>","lead":"Šesť klientok, ktoré nám dovolili podeliť sa o ich fotky. Look napravo je vždy ten, ktorý si odniesli zo salónu — neupravený doma znova kvôli fotke.","b1":{"cat":"Jemné balayage · Ema","title":"Z box-dye na nenáročné jemné balayage","note":"Tri sedenia s odstupom 8 týždňov. Olaplex pri každej návšteve a žiadne fólie nad level 7."},"b2":{"cat":"Tvar dlhých vlasov · Ema","title":"Dĺžka zachovaná, váha odobratá a končeky obnovené","note":"Jediná návšteva. Ubrali sme dva centimetre dĺžky a 20 % váhy zo stredných partií."},"b3":{"cat":"Šediny · Lucia","title":"Z mesačných korekcií do jemného prirodzeného splývania","note":"Dve návštevy s polročným odstupom. Natiahli sme odrast a chladné tóny sme prepísali stredom dĺžky."},"b4":{"cat":"Svadobná skúška · Hana","title":"Voľný romantický účes na svadbu v Českom Krumlove","note":"Skúška v utorok, deň D v sobotu. Nevesta si želala, aby pri sluchách nebolo nič pripnuté."},"b5":{"cat":"Korekcia · Lucia","title":"Z mosadzného odtieňa späť na čistú chladnú blond","note":"Štvorhodinová korekcia so strand-testom týždeň vopred. Glaze osvieženie po štyroch týždňoch."},"b6":{"cat":"Prvý strih · Klára","title":"Prvý poriadny strih po dvoch rokoch — jemné vrstvenie a nová ofina","note":"Deväťdesiat minút bez farbenia. Vrstvy sme dorezali za sucha, aby sme videli, ako vlasy prirodzene padajú."}}},"book_pg":{"meta_title":"Online rezervácia · Salón Lumi","meta_desc":"Vyberte si službu, stylistku a čas — potvrdíme písomne do štyroch pracovných hodín. Pätnásťminútová konzultácia zadarmo je vždy súčasťou.","crumb_home":"Salón Lumi","crumb":"Online rezervácia","title":"Rezervujte si <em>návštevu</em>","lead":"Štyri krátke kroky. Potvrdíme vám písomne do 4 pracovných hodín a pred každým farbením je 15-minútová konzultácia zadarmo vždy súčasťou.","step1":{"num":"Krok 01","label":"Služba"},"step2":{"num":"Krok 02","label":"Stylistka"},"step3":{"num":"Krok 03","label":"Dátum a čas"},"step4":{"num":"Krok 04","label":"Vaše údaje"},"s1":{"title":"Čo môžeme pre vás <em>urobiť?</em>","lead":"Vyberte najbližšiu možnosť — doladíme spolu pri konzultácii. Príplatok za dlhé vlasy platí pri dĺžke pod stred chrbta.","o1":{"name":"Strih na mieru","meta":"90 min · s konzultáciou","price":"od 45 €"},"o2":{"name":"Strih dlhých vlasov","meta":"90 min · pre vlasy pod plecia","price":"od 55 €"},"o3":{"name":"Korekcia odrastov","meta":"90 min · korienky + glaze","price":"od 65 €"},"o4":{"name":"Plné jednotónové farbenie","meta":"2,5 h · od korienkov po končeky","price":"od 95 €"},"o5":{"name":"Plné balayage","meta":"3,5 h · maľované rukou","price":"od 180 €"},"o6":{"name":"Olaplex samostatne","meta":"45 min · obnova väzieb","price":"35 €"},"o7":{"name":"Svadobná skúška + deň","meta":"2 h · skúška + deň svadby","price":"od 280 €"},"o8":{"name":"Iba konzultácia","meta":"20 min · pred farbením alebo korekciou","price":"zadarmo"}},"s2":{"title":"Vyberte si <em>stylistku</em>","lead":"Alebo nechajte to na nás — odporučíme podľa služby, dĺžky vlasov a podľa toho, kto má v daný týždeň voľno.","any":{"name":"Vyberte za mňa","role":"Bez preferencie"},"ema":{"name":"Ema Nováková","role":"Top stylistka"},"lucia":{"name":"Lucia Veselá","role":"Farbenie"},"hana":{"name":"Hana Krajčová","role":"Svadby"},"klara":{"name":"Klára Dušková","role":"Junior · −20 %"}},"s3":{"title":"Vyberte <em>dátum a čas</em>","lead":"Aktuálny prehľad voľných termínov na nasledujúcich 10 pracovných dní. Sobotné popoludnia sa zvyčajne plnia ako prvé — na jar a v decembri rezervujte 3 týždne dopredu.","d1":"Ut 12. mája","d1c":"3 termíny","d2":"St 13. mája","d2c":"5 termínov","d3":"Št 14. mája","d3c":"obsadené","d4":"Pi 15. mája","d4c":"2 termíny","d5":"So 16. mája","d5c":"1 termín","d6":"Po 18. mája","d6c":"6 termínov"},"s4":{"title":"Pár <em>posledných údajov</em>","lead":"Potvrdenie pošleme SMS-kou do 4 pracovných hodín. Bezplatné zrušenie do 24 hodín pred návštevou.","f":{"name_label":"Vaše meno","name_ph":"Anna Nováková","phone_label":"Telefón","phone_ph":"+420 770 111 222","email_label":"E-mail","email_ph":"anna@example.cz","notes_label":"Niečo, čo by sme mali vedieť?","notes_ph":"Foto poslednej farby / citlivosti / preferovaná stylistka…"},"sum":{"title":"Vaša rezervácia","svc":"Služba","svcEmpty":"— vyberte službu","styl":"Stylistka","stylEmpty":"— ktorákoľvek","when":"Kedy","whenEmpty":"— vyberte dátum","price":"Cena","priceEmpty":"— stanovíme pri konzultácii"}},"actions":{"prev":"← Späť","next":"Pokračovať →"}}},"cs":{"meta":{"title":"Salón Lumi · prémiové kadeřnictví Praha","description":"Prémiové kadeřnictví v centru Prahy. Střih, barva a balayage v týmu, který vás umí poslouchat. Online rezervace — první konzultace zdarma."},"a11y":{"skip":"Přeskočit na obsah"},"nav":{"salon":"O nás","services":"Služby","team":"Tým","gallery":"Lookbook","contact":"Kontakt","book":"Rezervovat online","social":"Sociální sítě"},"hero":{"eyebrow":"Prémiové kadeřnictví · Praha 2","brand":"Salón","brand_italic":"Lumi","line":"Střih · Barva · Balayage · Péče","sub":"Kadeřnice, které vás opravdu poslouchají. Upřímná rada a střih nebo barva, které sedí jak vašim vlasům, tak vašemu každodennímu životu."},"marquee":{"i1":"Střihy na míru","i2":"Balayage a zesvětlení","i3":"Péče Olaplex","i4":"Svatební styling","i5":"První konzultace zdarma"},"about":{"label":"O salonu","title":"Malý pražský salon, kde se všechno točí kolem vás, vašich vlasů a výsledku","p1":"V centru Prahy od roku 2018. Tým se nemění, salon zůstává malý záměrně — vaše kadeřnice na vás má vždycky čas.","p2":"Specializujeme se na dlouhé vlasy a barvení, které pěkně zarůstá — balayage, foliage a jemný melír. Bez agresivního odbarvování."},"stats":{"s1":"let na Vinohradské","s2":"spokojených klientek","s3":"kadeřnic v týmu","s4":"nominací · BOMTON CUP"},"services":{"label":"Služby","title":"Péče, která <em>sedne do vašeho života</em>","lead":"Krátký přehled toho, co děláme — vyberte si, co je pro vás. První konzultace je vždycky zdarma a k ničemu vás nezavazuje.","s1":{"title":"Střihy na míru","desc":"Střih navržený podle tvaru obličeje, typu vlasů a toho, jak je reálně nosíte. Vždycky začneme krátkým rozhovorem o tom, co si představujete.","price":"Od <strong>35 €</strong>"},"s2":{"title":"Barvení a tónování","desc":"Odstín volíme tak, aby vypadal přirozeně, elegantně a sladěně — nikdy ne přes míru. Na vyžádání i bez amoniaku.","price":"Od <strong>65 €</strong>"},"s3":{"title":"Balayage a zesvětlení","desc":"Ručně malované pramínky, které dodají vlasům hloubku a trochu rozjasnění — bez ostrých kontrastů a bez náročného odrostu.","price":"Od <strong>95 €</strong>"},"s4":{"title":"Péče a regenerace","desc":"Olaplex, hair botox a bonding ošetření. Prémiová péče, kterou doporučíme jen tehdy, když ji vlasy opravdu potřebují.","price":"Od <strong>25 €</strong>"}},"quote":{"text":"Víme, <em>jak moc</em> na vlasech záleží. Proto začínáme rozhovorem, nikdy vás netlačíme do zbytečných služeb a odstín barvy vám ukážeme ještě před začátkem.","sub":"— tým Lumi"},"team":{"label":"Tým","title":"Za každou návštěvou stojí <em>zkušené ruce</em>","lead":"Malý tým, který je spolu už roky. Každá z nás se specializuje na něco jiného — vyberte si tu, jejíž styl je vám nejbližší.","p1":{"name":"Ema Nováková","role":"Top stylistka · 8 let"},"p2":{"name":"Lucia Veselá","role":"Specialistka na barvu · 6 let"},"p3":{"name":"Hana Krajčová","role":"Svatby a styling · 5 let"},"p4":{"name":"Klára Dušková","role":"Junior stylistka · 2 roky"}},"lookbook":{"label":"Lookbook","title":"Pár nedávných <em>proměn</em>","lead":"Malý výběr střihů a barevných proměn z posledních měsíců."},"reviews":{"label":"Hlasy klientek","title":"Co o nás <em>klientky říkají</em>","t1":{"quote":"Po první návštěvě jsem tam jednoduše zůstala chodit — jsem tam pravidelně už tři roky. Emě věřím své vlasy jako nikomu jinému ve městě.","name":"Dominika","role":"Klientka od 2021"},"t2":{"quote":"Nejlepší balayage v Praze. Je vidět, že opravdu vědí, co dělají. A nikdy mě netlačí do dražších služeb.","name":"Zuzana","role":"Klientka od 2020"},"t3":{"quote":"Příjemný interiér, dobrá káva, profesionální tým. Doporučuji je všem kamarádkám — a na dlouhé vlasy jsou top v Praze.","name":"Veronika","role":"Klientka od 2022"},"t4":{"quote":"Lucia mi v zimě udělala tmavší barvu, na léto jsme přešly na světlejší balayage. Pořád to vypadá úplně přirozeně. Děkuji!","name":"Petra","role":"Klientka od 2023"},"t5":{"quote":"Původně jsem tam šla jen na střih. Dnes tam chodí celá moje rodina — včetně mé dcery.","name":"Andrea","role":"Klientka od 2019"}},"faq":{"label":"FAQ","title":"Časté <em>otázky</em>","q1":"Jak dlouho dopředu se mám objednat?","a1":"Na střih obvykle týden, na barvení dva týdny. Před Vánoci a před létem počítejte raději se třemi týdny.","q2":"Děláte konzultace před první návštěvou?","a2":"Ano — 15 minut zdarma e-mailem nebo telefonicky. Stačí poslat pár fotek vlasů a my vám napíšeme, jestli to, co chcete, jde zařídit.","q3":"Kde se dá zaparkovat?","a3":"Modrá zóna přímo před salonem, nebo placený parkovací dům OC Flora 5 minut pěšky.","q4":"Berete platby kartou?","a4":"Ano — kartou, hotovostí, Apple Pay i Google Pay."},"contact":{"label":"Kontakt","title":"Dnes otevřeno do 19:00","lead":"Online rezervace funguje 24/7. Telefonicky nás zastihnete v rámci otevírací doby.","address":"Vinohradská 24, 120 00 Praha 2","hours_mon":"Po–Pá 9:00 – 19:00","hours_sat":"So 9:00 – 14:00","hours_sun":"Ne zavřeno","btn_call":"Zavolat"},"cookies":{"text":"Používáme cookies, abychom vám poskytli lepší zážitek.","accept":"Přijmout","decline":"Odmítnout"},"footer":{"rights":"© 2026 Salón Lumi","privacy":"Ochrana osobních údajů"},"svc_pg":{"meta_title":"Služby a ceník · Salón Lumi","meta_desc":"Kompletní nabídka a ceník — střihy, barvení, balayage, péče a svatební styling. Vždy s konzultací zdarma.","crumb_home":"Salón Lumi","crumb":"Služby","title":"Náš kompletní <em>ceník</em>","lead":"Každou návštěvu otevíráme krátkou konzultací zdarma. Ceny níže jsou orientační; konečnou cenu odsouhlasíme společně před začátkem.","cuts":{"num":"01 — Střihy","title":"Střihy <em>na míru</em>","desc":"Střih, který sedí vaší tváři, hustotě vlasů a tomu, jak vlasy reálně nosíte. Na závěr ukážeme krátký styling, aby look přežil i ráno doma.","r1":{"name":"Dámský střih na míru","desc":"Mytí, signature střih a styling. V ceně konzultace a jednoduchý plán péče po střihu.","time":"90 min","price":"od 45 €"},"r2":{"name":"Střih dlouhých vlasů","desc":"Specializovaný přístup pro vlasy pod ramena — jemné vrstvení, ošetření konečků a zachování délky.","time":"90 min","price":"od 55 €"},"r3":{"name":"Zastřižení ofiny","desc":"Údržbové zastřižení mezi plnými střihy — rezervujte do 6 týdnů od poslední návštěvy.","time":"20 min","price":"15 €"},"r4":{"name":"Pánský střih + vousy","desc":"Stříhání nůžkami nebo strojkem s finišem horkým ručníkem. Úprava vousů jako doplněk.","time":"45 min","price":"od 35 €"}},"col":{"num":"02 — Barvení","title":"Barvení a <em>tónování</em>","desc":"Pracujeme s Wellou, Olaplexem a bezamoniakovými systémy. Novým klientkám vždy děláme test a odstín ukážeme v denním světle ještě před začátkem.","r1":{"name":"Korekce odrostu","desc":"Údržbové barvení u kořínků, jemně sladěné s existujícím odstínem. Nejlépe 6–8 týdnů po poslední návštěvě.","time":"90 min","price":"od 65 €"},"r2":{"name":"Plné jednotónové barvení","desc":"Od kořínků po konečky v jednom zvoleném odstínu. V ceně i glaze finiš pro lesk.","time":"2,5 h","price":"od 95 €"},"r3":{"name":"Glaze / gloss","desc":"20-minutové ošetření na osvěžení tónu a lesku — ideální mezi barveními.","time":"30 min","price":"35 €"},"r4":{"name":"Integrace šedin","desc":"Jemné, nenápadné propojení šedin, které pěkně zarůstají. Bez ostré hranice u kořínků.","time":"2 h","price":"od 85 €"}},"bal":{"num":"03 — Balayage a zesvětlení","title":"Jemné <em>balayage</em> a zesvětlení","desc":"Naše signature služba. Malované rukou, nikdy ne ostré, vždy s podporou Olaplexu. Cena závisí na délce a hustotě — odsouhlasíme ji při konzultaci.","r1":{"name":"Částečné balayage","desc":"Pramínky kolem obličeje a u pěšinky. Ideální pro první balayage nebo jako nenáročné osvěžení.","time":"2,5 h","price":"od 120 €"},"r2":{"name":"Plné balayage","desc":"Malované rozjasnění po celé hlavě, finišované tónujícím glazem pro rozměr.","time":"3,5 h","price":"od 180 €"},"r3":{"name":"Foilyage / dimension","desc":"Balayage s fóliovými akcenty pro světlejší výsledek při zachování měkkých kořínků.","time":"3,5 h","price":"od 195 €"},"r4":{"name":"Korekce barvy","desc":"Pro klientky, které opravují předchozí službu. Vždy s placenou 30-min strand-test konzultací týden předem.","time":"podle rozsahu","price":"podle rozsahu"}},"care":{"num":"04 — Péče","title":"Oprava a <em>regenerace</em>","desc":"Salonní ošetření a domácí programy. Nedoporučujeme ošetření, která vlasy nepotřebují — raději přijdete méně často, než byste platily víc, než je třeba.","r1":{"name":"Olaplex samostatně","desc":"Cílené obnovení vazeb pro vlasy zatížené barvením, teplem nebo prodloužením. Doporučujeme každé 4–6 týdnů.","time":"45 min","price":"35 €"},"r2":{"name":"K18 hloubková maska","desc":"4-minutová peptidová maska, která obnovuje keratinové řetězce. Nejlépe v kombinaci s barvením.","time":"30 min","price":"42 €"},"r3":{"name":"Rituál pokožky","desc":"Hloubkové čištění pokožky s masáží — peeling, rozpuštění olejů a 12-min uvolnění tlakových bodů.","time":"40 min","price":"38 €"},"r4":{"name":"Svatební zkouška + den svatby","desc":"Předsvatební zkouška plus styling v den svatby. V ceně i úvodní videokonzultace podle moodboardu a doprava v rámci Prahy 1–10.","time":"2 návštěvy","price":"od 280 €"}},"add":{"title":"Běžné doplňky","lead":"Přidejte k jakékoliv službě při rezervaci. Doporučíme jen to, co vaše vlasy reálně potřebují.","a1":{"name":"Příplatek za dlouhé vlasy (pod střed zad)","price":"+15 €"},"a2":{"name":"Glaze osvěžení tónu","price":"+25 €"},"a3":{"name":"K18 in-shower booster","price":"+18 €"},"a4":{"name":"Styling fénováním","price":"+22 €"},"a5":{"name":"Tónování obočí","price":"+12 €"},"a6":{"name":"Olaplex No. 3 domů","price":"+28 €"}},"vou":{"eyebrow":"Dárek, který zůstává","title":"Salonní poukazy, <em>tištěné ručně</em>","text":"Poukaz na libovolnou službu nebo na otevřenou částku (od 30 €). Ručně tištěný na bavlněném papíře, hotový do 2 dnů. Platnost 12 měsíců.","cta":"Objednat poukaz →"}},"team_pg":{"meta_title":"Náš tým · Salón Lumi","meta_desc":"Poznejte stylistky Lumi — osm let praxe, čtyři nominace na BOMTON CUP a specializace na dlouhé vlasy, balayage a svatby.","crumb_home":"Salón Lumi","crumb":"Tým","title":"Pět stylistek, <em>jeden salon</em>","lead":"Malý, vědomě tichý tým. Každá z nás se specializuje na něco jiného — vyberte si tu, jejíž práce k vám mluví, nebo vás napárujeme při konzultaci.","m_yrs":"Roky","m_lang":"Jazyk","m_book":"Rezervovat u","m_book_cta":"Rezervovat →","s1":{"role":"Top stylistka · zakladatelka","name":"Ema Nováková","b1":"Ema založila Lumi v roce 2018 po sedmi letech v Berlíně a Praze. Wella Master Colour Expert, tři roky finalistka BOMTON CUP. Specialistka na dlouhé vrstvené vlasy.","b2":"Před prvním barvením vždy 15-minutová konzultace. V jedné návštěvě nezesvětluje víc než dva levely. Klientky chodí cca každých 6 týdnů.","t1":"Specialistka na dlouhé vlasy","t2":"Jemný balayage","t3":"Wella master colour","t4":"Svatební zkoušky","yrs":"8","lang":"CZ · EN"},"s2":{"role":"Specialistka na barvu","name":"Lucia Veselá","b1":"Naše rezidentní koloristka od 2020. Goldwell certifikace ve Vídni. V salonu vede korekce barev — práce na 4–5 hodin, vždy s předchozím strand-testem.","b2":"Specializuje se na integraci šedin — z měsíčních korekcí do tónu, který pěkně zarůstá. Když vás unavuje cyklus údržby, je její křeslo pro vás.","t1":"Korekce barvy","t2":"Integrace šedin","t3":"Goldwell certified","t4":"Glossing","yrs":"6","lang":"CZ · DE · EN"},"s3":{"role":"Svatby a editorial","name":"Hana Krajčová","b1":"V Lumi od 2021. Předtím čtyři sezony pro Czech Vogue a otevírala tým hotelu Augustine. Jaro–podzim svatby, v zimě editorialy.","b2":"Vždy se zkouškou — žádný den svatby bez přípravy. Cestuje na obřady po ČR i SR. Úvodní videokonzultace s moodboardem je v ceně.","t1":"Svatební styling","t2":"Editorial","t3":"Účes / event","t4":"Cestuje za svatbou","yrs":"5","lang":"SK · CZ · EN"},"s4":{"role":"Junior stylistka","name":"Klára Dušková","b1":"Učební poměr v Lumi dokončila v 2024, teď vede vlastní křeslo. Dva roky se učila u Emy, Olaplex Level 2.","b2":"Rezervace u Kláry je o 20 % nižší než seniorské sazby — chceme, aby rostla s klientkami, kterým se její styl líbí.","t1":"Střihy","t2":"Korekce odrostu","t3":"Olaplex Lvl 2","t4":"Junior cena","yrs":"2","lang":"CZ · EN"},"ba":{"label":"Před · Po","title":"Pár nedávných <em>proměn</em>","lead":"Šest klientek, které nám dovolily se podělit o jejich fotky. Look napravo je vždy ten, který si odnesly ze salonu — neupravený doma znovu kvůli fotce.","b1":{"cat":"Jemný balayage · Ema","title":"Z box-dye na nenáročný jemný balayage","note":"Tři sezení s odstupem 8 týdnů. Olaplex při každé návštěvě a žádné fólie nad level 7."},"b2":{"cat":"Tvar dlouhých vlasů · Ema","title":"Délka zachována, váha odebrána a konečky obnoveny","note":"Jediná návštěva. Ubraly jsme dva centimetry délky a 20 % váhy ze středních partií."},"b3":{"cat":"Šediny · Lucia","title":"Z měsíčních korekcí do jemného přirozeného splývání","note":"Dvě návštěvy s půlročním odstupem. Natáhly jsme odrost a chladné tóny propsaly středem délky."},"b4":{"cat":"Svatební zkouška · Hana","title":"Volný romantický účes na svatbu v Českém Krumlově","note":"Zkouška v úterý, den D v sobotu. Nevěsta si přála, aby u spánků nebylo nic připnuté."},"b5":{"cat":"Korekce · Lucia","title":"Z mosazného odstínu zpět na čistou chladnou blond","note":"Čtyřhodinová korekce se strand-testem týden předem. Glaze osvěžení po čtyřech týdnech."},"b6":{"cat":"První střih · Klára","title":"První pořádný střih po dvou letech — jemné vrstvení a nová ofina","note":"Devadesát minut bez barvení. Vrstvy jsme dořezaly za sucha, abychom viděly, jak vlasy přirozeně padají."}}},"book_pg":{"meta_title":"Online rezervace · Salón Lumi","meta_desc":"Vyberte si službu, stylistku a čas — potvrdíme písemně do čtyř pracovních hodin. Patnáctiminutová konzultace zdarma je vždy součástí.","crumb_home":"Salón Lumi","crumb":"Online rezervace","title":"Rezervujte si <em>návštěvu</em>","lead":"Čtyři krátké kroky. Potvrdíme vám písemně do 4 pracovních hodin a před každým barvením je 15-minutová konzultace zdarma vždy součástí.","step1":{"num":"Krok 01","label":"Služba"},"step2":{"num":"Krok 02","label":"Stylistka"},"step3":{"num":"Krok 03","label":"Datum a čas"},"step4":{"num":"Krok 04","label":"Vaše údaje"},"s1":{"title":"Co pro vás <em>můžeme udělat?</em>","lead":"Vyberte nejbližší možnost — doladíme společně při konzultaci. Příplatek za dlouhé vlasy platí při délce pod střed zad.","o1":{"name":"Střih na míru","meta":"90 min · s konzultací","price":"od 45 €"},"o2":{"name":"Střih dlouhých vlasů","meta":"90 min · pro vlasy pod ramena","price":"od 55 €"},"o3":{"name":"Korekce odrostu","meta":"90 min · kořínky + glaze","price":"od 65 €"},"o4":{"name":"Plné jednotónové barvení","meta":"2,5 h · od kořínků po konečky","price":"od 95 €"},"o5":{"name":"Plné balayage","meta":"3,5 h · malované rukou","price":"od 180 €"},"o6":{"name":"Olaplex samostatně","meta":"45 min · obnova vazeb","price":"35 €"},"o7":{"name":"Svatební zkouška + den","meta":"2 h · zkouška + den svatby","price":"od 280 €"},"o8":{"name":"Pouze konzultace","meta":"20 min · před barvením nebo korekcí","price":"zdarma"}},"s2":{"title":"Vyberte si <em>stylistku</em>","lead":"Nebo nechte na nás — doporučíme podle služby, délky vlasů a podle toho, kdo má v daný týden volno.","any":{"name":"Vyberte za mě","role":"Bez preference"},"ema":{"name":"Ema Nováková","role":"Top stylistka"},"lucia":{"name":"Lucia Veselá","role":"Barvení"},"hana":{"name":"Hana Krajčová","role":"Svatby"},"klara":{"name":"Klára Dušková","role":"Junior · −20 %"}},"s3":{"title":"Vyberte <em>datum a čas</em>","lead":"Aktuální přehled volných termínů na následujících 10 pracovních dnů. Sobotní odpoledne se obvykle plní jako první — na jaře a v prosinci rezervujte 3 týdny dopředu.","d1":"Út 12. května","d1c":"3 termíny","d2":"St 13. května","d2c":"5 termínů","d3":"Čt 14. května","d3c":"obsazeno","d4":"Pá 15. května","d4c":"2 termíny","d5":"So 16. května","d5c":"1 termín","d6":"Po 18. května","d6c":"6 termínů"},"s4":{"title":"Pár <em>posledních údajů</em>","lead":"Potvrzení pošleme SMS do 4 pracovních hodin. Bezplatné zrušení do 24 hodin před návštěvou.","f":{"name_label":"Vaše jméno","name_ph":"Anna Nováková","phone_label":"Telefon","phone_ph":"+420 770 111 222","email_label":"E-mail","email_ph":"anna@example.cz","notes_label":"Něco, co bychom měly vědět?","notes_ph":"Foto poslední barvy / citlivosti / preferovaná stylistka…"},"sum":{"title":"Vaše rezervace","svc":"Služba","svcEmpty":"— vyberte službu","styl":"Stylistka","stylEmpty":"— kterákoliv","when":"Kdy","whenEmpty":"— vyberte datum","price":"Cena","priceEmpty":"— stanovíme při konzultaci"}},"actions":{"prev":"← Zpět","next":"Pokračovat →"}}}};